import { callMcpSkill, callMcpSkillsParallel } from "@/lib/ai/skills/mcp";
import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";
  const marketQuery = "Will the U.S. invade Iran before 2027?";

  // Probe: resolve the exact market first, then deterministically target the best candidate.
  const discovery = await callMcpSkill({
    toolId,
    toolName: "search_markets",
    args: {
      query: marketQuery,
      status: "live",
      category: "politics",
      limit: 10
    }
  });

  const candidates = Array.isArray(discovery?.results) ? discovery.results : [];
  const ranked = pickTopSemanticCandidates({
    target: marketQuery,
    candidates,
    requiredTerms: ["Iran", "2027"],
    avoidTerms: ["election", "primary", "candidate", "district"],
    limit: 1
  });

  const selected = ranked[0] || candidates[0] || null;
  const conditionId = selected?.conditionId || null;
  const slug = selected?.slug || null;

  if (!conditionId && !slug) {
    return {
      missingData: ["conditionId", "slug"],
      attemptedBranches: ["search_markets → semantic targeting"],
      stopReason: "No direct market instrument could be resolved from the discovery batch."
    };
  }

  // Execute independent read-only endpoint calls in parallel only after the shortlist is fixed.
  const primaryBatch = await callMcpSkillsParallel({
    label: "iran-market-readonly-batch",
    calls: [
      {
        key: "whales",
        toolId,
        toolName: "analyze_single_market_whales",
        args: conditionId ? { conditionId, marketQuery } : { slug, marketQuery }
      },
      {
        key: "oiNow",
        toolId,
        toolName: "get_market_open_interest",
        args: conditionId ? { conditionId } : { conditionId: null, conditionIds: [] }
      },
      {
        key: "rules",
        toolId,
        toolName: "check_market_rules",
        args: conditionId ? { conditionId } : { slug, marketQuery }
      }
    ]
  });

  const byKey = Object.fromEntries(
    primaryBatch.results.map((entry) => [
      entry.key,
      entry.status === "fulfilled" ? entry.value : null
    ])
  );

  const whales = byKey.whales;
  const oiNow = byKey.oiNow;
  const rules = byKey.rules;

  const resolvedConditionId =
    whales?.selectedMarket?.conditionId ||
    conditionId ||
    oiNow?.openInterest?.[0]?.conditionId ||
    null;

  // Bounded fallback for OI trend: take a second snapshot later, then compute delta/rate locally.
  const oiThen = resolvedConditionId
    ? await callMcpSkill({
        toolId,
        toolName: "get_market_open_interest",
        args: { conditionId: resolvedConditionId }
      })
    : null;

  const currentPrice = whales?.selectedMarket?.currentPrice ?? null;
  const whaleFlow = whales?.whaleFlow || null;
  const holderAnalysis = whales?.holderAnalysis || null;
  const concentration = holderAnalysis?.marketConcentration || null;
  const smartMoney = holderAnalysis?.smartMoneySignal || null;

  const oiRowsNow = Array.isArray(oiNow?.openInterest) ? oiNow.openInterest : [];
  const oiRowsThen = Array.isArray(oiThen?.openInterest) ? oiThen.openInterest : [];
  const oiValueNow =
    oiRowsNow.find((row) => row.conditionId === resolvedConditionId)?.value ??
    oiRowsNow[0]?.value ??
    null;
  const oiValueThen =
    oiRowsThen.find((row) => row.conditionId === resolvedConditionId)?.value ??
    oiRowsThen[0]?.value ??
    null;

  const oiDelta =
    typeof oiValueNow === "number" && typeof oiValueThen === "number"
      ? oiValueNow - oiValueThen
      : null;

  const oiTrend =
    oiDelta === null
      ? null
      : {
          current: oiValueNow,
          previous: oiValueThen,
          delta: oiDelta,
          direction: oiDelta > 0 ? "up" : oiDelta < 0 ? "down" : "flat"
        };

  const whaleFlowDirection = whaleFlow?.divergence || whaleFlow?.whaleActivity?.sentiment || null;
  const agreesWithPrice =
    typeof currentPrice === "number" && whaleFlowDirection
      ? {
          currentPrice,
          priceBand: currentPrice <= 0.24 ? "at_or_below_24c" : "above_24c",
          whaleFlowDirection,
          agreement:
            (currentPrice <= 0.24 && /buying|bullish|YES/i.test(String(whaleFlowDirection))) ||
            (currentPrice > 0.24 && /selling|bearish|NO/i.test(String(whaleFlowDirection)))
              ? "agree"
              : "disagree_or_mixed"
        }
      : null;

  return {
    market: whales?.selectedMarket?.title || selected?.title || marketQuery,
    conditionId: resolvedConditionId,
    currentPrice,
    concentration,
    topHolders: {
      yes: Array.isArray(whales?.yesWhales) ? whales.yesWhales.slice(0, 5) : [],
      no: Array.isArray(whales?.noWhales) ? whales.noWhales.slice(0, 5) : []
    },
    whaleFlow: whaleFlow
      ? {
          period: whaleFlow.period,
          totalTrades: whaleFlow.totalTrades,
          totalVolume: whaleFlow.totalVolume,
          divergence: whaleFlow.divergence,
          flowBySize: whaleFlow.flowBySize,
          whaleActivity: whaleFlow.whaleActivity
        }
      : null,
    openInterest: {
      now: oiValueNow,
      previous: oiValueThen,
      trend: oiTrend,
      fetchedAtNow: oiNow?.fetchedAt || null,
      fetchedAtPrevious: oiThen?.fetchedAt || null,
      changeRateAvailable: oiNow?.changeRateAvailable ?? false
    },
    agreementWith24CentPrice: agreesWithPrice,
    rules: rules
      ? {
          description: rules.description,
          riskFactors: rules.riskFactors,
          resolvesYesIf: rules.rulesSummary?.resolvesYesIf,
          resolvesNoIf: rules.rulesSummary?.resolvesNoIf,
          potentialGotchas: rules.rulesSummary?.potentialGotchas
        }
      : null,
    selection: {
      discoveryCount: candidates.length,
      shortlisted: selected
        ? {
            title: selected.title,
            slug: selected.slug || null,
            conditionId: selected.conditionId || null
          }
        : null
    },
    analysisNotes: [
      "This plan uses direct market discovery first, then deterministic semantic targeting before any detail calls.",
      "Top-holder concentration and recent whale flow come from the whale analysis path; open-interest change is handled by a bounded two-snapshot comparison, not a single snapshot.",
      "Local comparison of whale flow vs the 24-cent price is computed explicitly from the raw fields."
    ],
    parallelTelemetry: primaryBatch.summary
  };
}

